import {
  Box,
  Wrap,
  WrapItem,
  Skeleton,
  SkeletonText,
  Tag,
  Heading,
  Text,
  Link,
  HStack,
} from "@chakra-ui/react";
import { ExternalLinkIcon } from "@chakra-ui/icons";

const InfoBox = (props) => {
  const renderTags = () => {
    if (props.tags !== undefined) {
      return props.tags.map((tag, i) => (
        <Tag key={i} colorScheme="telegram" variant="solid">
          {tag}
        </Tag>
      ));
    }
  };

  return (
    <Box>
      <Wrap justify="space-between" mb={2}>
        <WrapItem>
          <Heading fontSize="24px">
            <Link href={props.link}>
              {props.title}
              <ExternalLinkIcon ml={2} pb={1} w={6} h={6} />
            </Link>
          </Heading>
        </WrapItem>
        <WrapItem>
          <Text mt={1}>{props.time}</Text>
        </WrapItem>
      </Wrap>

      <HStack spacing="16px">{renderTags()}</HStack>

      <Text mt={1}>{props.description}</Text>
    </Box>
  );
};

export default InfoBox;
